      "arguments": {
        "resource": "contract_modification",
        "action": "update",
        "context": {
          "vendor": "TechFlow Solutions",
          "operation": "term_extension",
          "extension_months": 12
        }
      },
      "depends_on": []
    },
    {
      "tool": "mongo.find",
      "arguments": {
        "collection": "contracts",
        "filter": {
          "vendor_name": "TechFlow Solutions"
        }
      },
      "depends_on": [1]
    },
    {
      "tool": "mongo.update",
      "arguments": {
        "collection": "contracts",
        "filter": {
          "vendor_name": "TechFlow Solutions"
        },
        "update": {
